3	/**
4	 * tb_cross_layer_ft2232h.v
5	 *
6	 * Cross-layer contract testbench for the FT2232H USB interface.
7	 * Exercises three packet types with known distinctive values and dumps
8	 * captured bytes to text files that the Python orchestrator can parse.
9	 *
10	 * Exercise A: Command round-trip (Host -> FPGA)
11	 *   - Send every opcode through the 4-byte read FSM
12	 *   - Dump cmd_opcode, cmd_addr, cmd_value to cmd_results.txt
13	 *
14	 * Exercise B: Data packet generation (FPGA -> Host)
15	 *   - Inject known range/doppler/cfar values
16	 *   - Capture all 11 output bytes
17	 *   - Dump to data_packet.txt
18	 *
19	 * Exercise C: Status packet generation (FPGA -> Host)
20	 *   - Set all status inputs to known non-zero values
21	 *   - Trigger status request
22	 *   - Capture all 26 output bytes
23	 *   - Dump to status_packet.txt
24	 */
25	
26	module tb_cross_layer_ft2232h;
27	
28	    // Clock periods
29	    localparam CLK_PERIOD    = 10.0;   // 100 MHz system clock
30	    localparam FT_CLK_PERIOD = 16.67;  // 60 MHz FT2232H clock
31	
32	    // ---- Signals ----
33	    reg         clk;
34	    reg         reset_n;
35	    reg         ft_reset_n;
36	
37	    // Radar data inputs
38	    reg  [31:0] range_profile;
39	    reg         range_valid;
40	    reg  [15:0] doppler_real;
41	    reg  [15:0] doppler_imag;
42	    reg         doppler_valid;
43	    reg         cfar_detection;
44	    reg         cfar_valid;
45	
46	    // FT2232H physical interface
47	    wire [7:0]  ft_data;
48	    reg         ft_rxf_n;
49	    reg         ft_txe_n;
50	    wire        ft_rd_n;
51	    wire        ft_wr_n;
52	    wire        ft_oe_n;
53	    wire        ft_siwu;
54	    reg         ft_clk;
55	
56	    // Host-side bus driver (for command injection)
57	    reg  [7:0]  host_data_drive;
58	    reg         host_data_drive_en;
59	    assign ft_data = host_data_drive_en ? host_data_drive : 8'hZZ;
60	
61	    // Pulldown to avoid X during idle
62	    pulldown pd[7:0] (ft_data);
63	
64	    // DUT command outputs
65	    wire [31:0] cmd_data;
66	    wire        cmd_valid;
67	    wire [7:0]  cmd_opcode;
68	    wire [7:0]  cmd_addr;
69	    wire [15:0] cmd_value;
70	
71	    // Stream control
72	    reg  [2:0]  stream_control;
73	
74	    // Status inputs
75	    reg         status_request;
76	    reg  [15:0] status_cfar_threshold;
77	    reg  [2:0]  status_stream_ctrl;
78	    reg  [1:0]  status_radar_mode;
79	    reg  [15:0] status_long_chirp;
80	    reg  [15:0] status_long_listen;
81	    reg  [15:0] status_guard;
82	    reg  [15:0] status_short_chirp;
83	    reg  [15:0] status_short_listen;
84	    reg  [5:0]  status_chirps_per_elev;
85	    reg  [1:0]  status_range_mode;
86	    reg  [4:0]  status_self_test_flags;
87	    reg  [7:0]  status_self_test_detail;
88	    reg         status_self_test_busy;
89	    reg  [3:0]  status_agc_current_gain;
90	    reg  [7:0]  status_agc_peak_magnitude;
91	    reg  [7:0]  status_agc_saturation_count;
92	    reg         status_agc_enable;
93	
94	    // ---- Clock generators ----
95	    always #(CLK_PERIOD / 2)    clk    = ~clk;
96	    always #(FT_CLK_PERIOD / 2) ft_clk = ~ft_clk;
97	
98	    // ---- DUT instantiation ----
99	    usb_data_interface_ft2232h uut (
100	        .clk                    (clk),
101	        .reset_n                (reset_n),
102	        .ft_reset_n             (ft_reset_n),
103	        .range_profile          (range_profile),
104	        .range_valid            (range_valid),
105	        .doppler_real           (doppler_real),
106	        .doppler_imag           (doppler_imag),
107	        .doppler_valid          (doppler_valid),
108	        .cfar_detection         (cfar_detection),
109	        .cfar_valid             (cfar_valid),
110	        .ft_data                (ft_data),
111	        .ft_rxf_n               (ft_rxf_n),
112	        .ft_txe_n               (ft_txe_n),
113	        .ft_rd_n                (ft_rd_n),
114	        .ft_wr_n                (ft_wr_n),
115	        .ft_oe_n                (ft_oe_n),
116	        .ft_siwu                (ft_siwu),
117	        .ft_clk                 (ft_clk),
118	        .cmd_data               (cmd_data),
119	        .cmd_valid              (cmd_valid),
120	        .cmd_opcode             (cmd_opcode),
121	        .cmd_addr               (cmd_addr),
122	        .cmd_value              (cmd_value),
123	        .stream_control         (stream_control),
124	        .status_request         (status_request),
125	        .status_cfar_threshold  (status_cfar_threshold),
126	        .status_stream_ctrl     (status_stream_ctrl),
127	        .status_radar_mode      (status_radar_mode),
128	        .status_long_chirp      (status_long_chirp),
129	        .status_long_listen     (status_long_listen),
130	        .status_guard           (status_guard),
131	        .status_short_chirp     (status_short_chirp),
132	        .status_short_listen    (status_short_listen),
133	        .status_chirps_per_elev (status_chirps_per_elev),
134	        .status_range_mode      (status_range_mode),
135	        .status_self_test_flags (status_self_test_flags),
136	        .status_self_test_detail(status_self_test_detail),
137	        .status_self_test_busy  (status_self_test_busy),
138	        .status_agc_current_gain    (status_agc_current_gain),
139	        .status_agc_peak_magnitude  (status_agc_peak_magnitude),
140	        .status_agc_saturation_count(status_agc_saturation_count),
141	        .status_agc_enable          (status_agc_enable)
142	    );
143	
144	    // ---- Test bookkeeping ----
145	    integer pass_count;
146	    integer fail_count;
147	    integer test_num;
148	    integer cmd_file;
149	    integer data_file;
150	    integer status_file;
151	
152	    // ---- Check task ----
153	    task check;
154	        input cond;
155	        input [511:0] label;
156	        begin
157	            test_num = test_num + 1;
158	            if (cond) begin
159	                $display("[PASS] Test %0d: %0s", test_num, label);
160	                pass_count = pass_count + 1;
161	            end else begin
162	                $display("[FAIL] Test %0d: %0s", test_num, label);
163	                fail_count = fail_count + 1;
164	            end
165	        end
166	    endtask
167	
168	    // ---- Helper: apply reset ----
169	    task apply_reset;
170	        begin
171	            reset_n          = 0;
172	            ft_reset_n       = 0;
173	            range_profile    = 32'h0;
174	            range_valid      = 0;
175	            doppler_real     = 16'h0;
176	            doppler_imag     = 16'h0;
177	            doppler_valid    = 0;
178	            cfar_detection   = 0;
179	            cfar_valid       = 0;
180	            ft_rxf_n         = 1;    // No host data available
181	            ft_txe_n         = 0;    // TX FIFO ready
182	            host_data_drive  = 8'h0;
183	            host_data_drive_en = 0;
184	            stream_control        = 3'b111;
185	            status_request        = 0;
186	            status_cfar_threshold = 16'd0;
187	            status_stream_ctrl    = 3'b000;
188	            status_radar_mode     = 2'b00;
189	            status_long_chirp     = 16'd0;
190	            status_long_listen    = 16'd0;
191	            status_guard          = 16'd0;
192	            status_short_chirp    = 16'd0;
193	            status_short_listen   = 16'd0;
194	            status_chirps_per_elev = 6'd0;
195	            status_range_mode     = 2'b00;
196	            status_self_test_flags  = 5'b00000;
197	            status_self_test_detail = 8'd0;
198	            status_self_test_busy   = 1'b0;
199	            status_agc_current_gain     = 4'd0;
200	            status_agc_peak_magnitude   = 8'd0;
201	            status_agc_saturation_count = 8'd0;
202	            status_agc_enable           = 1'b0;
203	            repeat (6) @(posedge ft_clk);
204	            reset_n    = 1;
205	            ft_reset_n = 1;
206	            // Wait for stream_control CDC to propagate
207	            repeat (8) @(posedge ft_clk);
208	        end
209	    endtask
210	
211	    // ---- Helper: send one 4-byte command via FT2232H read path ----
212	    //
213	    // FT2232H read FSM cycle-by-cycle:
214	    //   Cycle 0 (RD_IDLE):      sees !ft_rxf_n → ft_oe_n<=0, → RD_OE_ASSERT
215	    //   Cycle 1 (RD_OE_ASSERT): sees !ft_rxf_n → ft_rd_n<=0, → RD_READING
216	    //   Cycle 2 (RD_READING):   samples ft_data=byte0, cnt 0→1
217	    //   Cycle 3 (RD_READING):   samples ft_data=byte1, cnt 1→2
218	    //   Cycle 4 (RD_READING):   samples ft_data=byte2, cnt 2→3
219	    //   Cycle 5 (RD_READING):   samples ft_data=byte3, cnt=3→0, → RD_DEASSERT
220	    //   Cycle 6 (RD_DEASSERT):  ft_oe_n<=1, → RD_PROCESS
221	    //   Cycle 7 (RD_PROCESS):   cmd_valid<=1, decode, → RD_IDLE
222	    //
223	    // Data must be stable BEFORE the sampling posedge. We use #1 after
224	    // posedge to change data in the "delta after" region.
225	    task send_command_ft2232h;
226	        input [7:0] byte0;  // opcode
227	        input [7:0] byte1;  // addr
228	        input [7:0] byte2;  // value_hi
229	        input [7:0] byte3;  // value_lo
230	        begin
231	            // Pre-drive byte0 and signal data available
232	            @(posedge ft_clk); #1;
233	            host_data_drive    = byte0;
234	            host_data_drive_en = 1;
235	            ft_rxf_n           = 0;
236	
237	            // Cycle 0: RD_IDLE sees !ft_rxf_n, goes to OE_ASSERT
238	            @(posedge ft_clk); #1;
239	
240	            // Cycle 1: RD_OE_ASSERT, ft_rd_n goes low, goes to RD_READING
241	            @(posedge ft_clk); #1;
242	
243	            // Cycle 2: RD_READING, byte0 is sampled, cnt 0→1
244	            // Now change to byte1 for next sample
245	            @(posedge ft_clk); #1;
246	            host_data_drive = byte1;
247	
248	            // Cycle 3: RD_READING, byte1 is sampled, cnt 1→2
249	            @(posedge ft_clk); #1;
250	            host_data_drive = byte2;
251	
252	            // Cycle 4: RD_READING, byte2 is sampled, cnt 2→3
253	            @(posedge ft_clk); #1;
254	            host_data_drive = byte3;
255	
256	            // Cycle 5: RD_READING, byte3 is sampled, cnt=3, → RD_DEASSERT
257	            @(posedge ft_clk); #1;
258	
259	            // Cycle 6: RD_DEASSERT, ft_oe_n←1, → RD_PROCESS
260	            @(posedge ft_clk); #1;
261	
262	            // Cycle 7: RD_PROCESS, cmd decoded, cmd_valid←1, → RD_IDLE
263	            @(posedge ft_clk); #1;
264	
265	            // cmd_valid was asserted at cycle 7's posedge. cmd_opcode/addr/value
266	            // are now valid (registered outputs hold until next RD_PROCESS).
267	
268	            // Release bus
269	            host_data_drive_en = 0;
270	            host_data_drive    = 8'h0;
271	            ft_rxf_n           = 1;
272	
273	            // Settle
274	            repeat (2) @(posedge ft_clk);
275	        end
276	    endtask
277	
278	    // ---- Helper: capture N write bytes from the DUT ----
279	    // Monitors ft_wr_n and ft_data_out, captures bytes into array.
280	    // Used for data packets (11 bytes) and status packets (26 bytes).
281	    reg [7:0] captured_bytes [0:31];
282	    integer   capture_count;
283	
284	    task capture_write_bytes;
285	        input integer expected_count;
286	        integer timeout;
287	        begin
288	            capture_count = 0;
289	            timeout = 0;
290	
291	            while (capture_count < expected_count && timeout < 2000) begin
292	                @(posedge ft_clk); #1;
293	                timeout = timeout + 1;
294	                // DUT drives byte when ft_wr_n=0 and ft_data_oe=1
295	                // Sample AFTER posedge so registered outputs are settled
296	                if (!ft_wr_n && uut.ft_data_oe) begin
297	                    captured_bytes[capture_count] = uut.ft_data_out;
298	                    capture_count = capture_count + 1;
299	                end
300	            end
301	        end
302	    endtask
303	
304	    // ---- Helper: pulse range_valid with CDC wait ----
305	    // Toggle CDC needs 3 sync stages + edge detect = 4+ ft_clk cycles.
306	    // Use 12 for safety margin.
307	    task assert_range_valid;
308	        input [31:0] data;
309	        begin
310	            @(posedge clk); #1;
311	            range_profile = data;
312	            range_valid   = 1;
313	            @(posedge clk); #1;
314	            range_valid   = 0;
315	            // Wait for toggle CDC propagation
316	            repeat (12) @(posedge ft_clk);
317	        end
318	    endtask
319	
320	    // ---- Helper: pulse doppler_valid ----
321	    task pulse_doppler;
322	        input [15:0] dr;
323	        input [15:0] di;
324	        begin
325	            @(posedge clk); #1;
326	            doppler_real  = dr;
327	            doppler_imag  = di;
328	            doppler_valid = 1;
329	            @(posedge clk); #1;
330	            doppler_valid = 0;
331	            repeat (12) @(posedge ft_clk);
332	        end
333	    endtask
334	
335	    // ---- Helper: pulse cfar_valid ----
336	    task pulse_cfar;
337	        input det;
338	        begin
339	            @(posedge clk); #1;
340	            cfar_detection = det;
341	            cfar_valid     = 1;
342	            @(posedge clk); #1;
343	            cfar_valid     = 0;
344	            repeat (12) @(posedge ft_clk);
345	        end
346	    endtask
347	
348	    // ---- Helper: pulse status_request ----
349	    task pulse_status_request;
350	        begin
351	            @(posedge clk); #1;
352	            status_request = 1;
353	            @(posedge clk); #1;
354	            status_request = 0;
355	            // Wait for toggle CDC propagation
356	            repeat (12) @(posedge ft_clk);
357	        end
358	    endtask
359	
360	    // ================================================================
361	    // Main stimulus
362	    // ================================================================
363	    integer i;
364	
365	    initial begin
366	        $dumpfile("tb_cross_layer_ft2232h.vcd");
367	        $dumpvars(0, tb_cross_layer_ft2232h);
368	
369	        clk    = 0;
370	        ft_clk = 0;
371	        pass_count = 0;
372	        fail_count = 0;
373	        test_num   = 0;
374	
375	        // ============================================================
376	        // EXERCISE A: Command Round-Trip
377	        // Send commands with known opcode/addr/value, verify decoding.
378	        // Dump results to cmd_results.txt for Python validation.
379	        // ============================================================
380	        $display("\n=== EXERCISE A: Command Round-Trip ===");
381	        apply_reset;
382	
383	        cmd_file = $fopen("cmd_results.txt", "w");
384	        $fwrite(cmd_file, "# opcode_sent addr_sent value_sent opcode_got addr_got value_got\n");
385	
386	        // Test all real opcodes from radar_system_top.v
387	        // Format: opcode, addr=0x00, value
388	
389	        // Basic control
390	        send_command_ft2232h(8'h01, 8'h00, 8'h00, 8'h02);  // RADAR_MODE=2
391	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
392	                8'h01, 8'h00, 16'h0002, cmd_opcode, cmd_addr, cmd_value);
393	        check(cmd_opcode === 8'h01 && cmd_value === 16'h0002,
394	              "Cmd 0x01: RADAR_MODE=2");
395	
396	        send_command_ft2232h(8'h02, 8'h00, 8'h00, 8'h01);  // TRIGGER_PULSE
397	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
398	                8'h02, 8'h00, 16'h0001, cmd_opcode, cmd_addr, cmd_value);
399	        check(cmd_opcode === 8'h02 && cmd_value === 16'h0001,
400	              "Cmd 0x02: TRIGGER_PULSE");
401	
402	        send_command_ft2232h(8'h03, 8'h00, 8'h27, 8'h10);  // DETECT_THRESHOLD=10000
403	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
404	                8'h03, 8'h00, 16'h2710, cmd_opcode, cmd_addr, cmd_value);
405	        check(cmd_opcode === 8'h03 && cmd_value === 16'h2710,
406	              "Cmd 0x03: DETECT_THRESHOLD=10000");
407	
408	        send_command_ft2232h(8'h04, 8'h00, 8'h00, 8'h07);  // STREAM_CONTROL=7
409	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
410	                8'h04, 8'h00, 16'h0007, cmd_opcode, cmd_addr, cmd_value);
411	        check(cmd_opcode === 8'h04 && cmd_value === 16'h0007,
412	              "Cmd 0x04: STREAM_CONTROL=7");
413	
414	        // Chirp timing
415	        send_command_ft2232h(8'h10, 8'h00, 8'h0B, 8'hB8);  // LONG_CHIRP=3000
416	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
417	                8'h10, 8'h00, 16'h0BB8, cmd_opcode, cmd_addr, cmd_value);
418	        check(cmd_opcode === 8'h10 && cmd_value === 16'h0BB8,
419	              "Cmd 0x10: LONG_CHIRP=3000");
420	
421	        send_command_ft2232h(8'h11, 8'h00, 8'h35, 8'h84);  // LONG_LISTEN=13700
422	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
423	                8'h11, 8'h00, 16'h3584, cmd_opcode, cmd_addr, cmd_value);
424	        check(cmd_opcode === 8'h11 && cmd_value === 16'h3584,
425	              "Cmd 0x11: LONG_LISTEN=13700");
426	
427	        send_command_ft2232h(8'h12, 8'h00, 8'h44, 8'h84);  // GUARD=17540
428	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
429	                8'h12, 8'h00, 16'h4484, cmd_opcode, cmd_addr, cmd_value);
430	        check(cmd_opcode === 8'h12 && cmd_value === 16'h4484,
431	              "Cmd 0x12: GUARD=17540");
432	
433	        send_command_ft2232h(8'h13, 8'h00, 8'h00, 8'h32);  // SHORT_CHIRP=50
434	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
435	                8'h13, 8'h00, 16'h0032, cmd_opcode, cmd_addr, cmd_value);
436	        check(cmd_opcode === 8'h13 && cmd_value === 16'h0032,
437	              "Cmd 0x13: SHORT_CHIRP=50");
438	
439	        send_command_ft2232h(8'h14, 8'h00, 8'h44, 8'h2A);  // SHORT_LISTEN=17450
440	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
441	                8'h14, 8'h00, 16'h442A, cmd_opcode, cmd_addr, cmd_value);
442	        check(cmd_opcode === 8'h14 && cmd_value === 16'h442A,
443	              "Cmd 0x14: SHORT_LISTEN=17450");
444	
445	        send_command_ft2232h(8'h15, 8'h00, 8'h00, 8'h20);  // CHIRPS_PER_ELEV=32
446	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
447	                8'h15, 8'h00, 16'h0020, cmd_opcode, cmd_addr, cmd_value);
448	        check(cmd_opcode === 8'h15 && cmd_value === 16'h0020,
449	              "Cmd 0x15: CHIRPS_PER_ELEV=32");
450	
451	        // Digital gain
452	        send_command_ft2232h(8'h16, 8'h00, 8'h00, 8'h05);  // GAIN_SHIFT=5
453	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
454	                8'h16, 8'h00, 16'h0005, cmd_opcode, cmd_addr, cmd_value);
455	        check(cmd_opcode === 8'h16 && cmd_value === 16'h0005,
456	              "Cmd 0x16: GAIN_SHIFT=5");
457	
458	        // Signal processing
459	        send_command_ft2232h(8'h20, 8'h00, 8'h00, 8'h01);  // RANGE_MODE=1
460	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
461	                8'h20, 8'h00, 16'h0001, cmd_opcode, cmd_addr, cmd_value);
462	        check(cmd_opcode === 8'h20 && cmd_value === 16'h0001,
463	              "Cmd 0x20: RANGE_MODE=1");
464	
465	        send_command_ft2232h(8'h21, 8'h00, 8'h00, 8'h03);  // CFAR_GUARD=3
466	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
467	                8'h21, 8'h00, 16'h0003, cmd_opcode, cmd_addr, cmd_value);
468	        check(cmd_opcode === 8'h21 && cmd_value === 16'h0003,
469	              "Cmd 0x21: CFAR_GUARD=3");
470	
471	        send_command_ft2232h(8'h22, 8'h00, 8'h00, 8'h0C);  // CFAR_TRAIN=12
472	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
473	                8'h22, 8'h00, 16'h000C, cmd_opcode, cmd_addr, cmd_value);
474	        check(cmd_opcode === 8'h22 && cmd_value === 16'h000C,
475	              "Cmd 0x22: CFAR_TRAIN=12");
476	
477	        send_command_ft2232h(8'h23, 8'h00, 8'h00, 8'h30);  // CFAR_ALPHA=0x30
478	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
479	                8'h23, 8'h00, 16'h0030, cmd_opcode, cmd_addr, cmd_value);
480	        check(cmd_opcode === 8'h23 && cmd_value === 16'h0030,
481	              "Cmd 0x23: CFAR_ALPHA=0x30");
482	
483	        send_command_ft2232h(8'h24, 8'h00, 8'h00, 8'h01);  // CFAR_MODE=1 (GO)
484	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
485	                8'h24, 8'h00, 16'h0001, cmd_opcode, cmd_addr, cmd_value);
486	        check(cmd_opcode === 8'h24 && cmd_value === 16'h0001,
487	              "Cmd 0x24: CFAR_MODE=1");
488	
489	        send_command_ft2232h(8'h25, 8'h00, 8'h00, 8'h01);  // CFAR_ENABLE=1
490	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
491	                8'h25, 8'h00, 16'h0001, cmd_opcode, cmd_addr, cmd_value);
492	        check(cmd_opcode === 8'h25 && cmd_value === 16'h0001,
493	              "Cmd 0x25: CFAR_ENABLE=1");
494	
495	        send_command_ft2232h(8'h26, 8'h00, 8'h00, 8'h01);  // MTI_ENABLE=1
496	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
497	                8'h26, 8'h00, 16'h0001, cmd_opcode, cmd_addr, cmd_value);
498	        check(cmd_opcode === 8'h26 && cmd_value === 16'h0001,
499	              "Cmd 0x26: MTI_ENABLE=1");
500	
501	        send_command_ft2232h(8'h27, 8'h00, 8'h00, 8'h03);  // DC_NOTCH_WIDTH=3
502	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
503	                8'h27, 8'h00, 16'h0003, cmd_opcode, cmd_addr, cmd_value);
504	        check(cmd_opcode === 8'h27 && cmd_value === 16'h0003,
505	              "Cmd 0x27: DC_NOTCH_WIDTH=3");
506	
507	        // AGC registers (0x28-0x2C)
508	        send_command_ft2232h(8'h28, 8'h00, 8'h00, 8'h01);  // AGC_ENABLE=1
509	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
510	                8'h28, 8'h00, 16'h0001, cmd_opcode, cmd_addr, cmd_value);
511	        check(cmd_opcode === 8'h28 && cmd_value === 16'h0001,
512	              "Cmd 0x28: AGC_ENABLE=1");
513	
514	        send_command_ft2232h(8'h29, 8'h00, 8'h00, 8'hC8);  // AGC_TARGET=200
515	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
516	                8'h29, 8'h00, 16'h00C8, cmd_opcode, cmd_addr, cmd_value);
517	        check(cmd_opcode === 8'h29 && cmd_value === 16'h00C8,
518	              "Cmd 0x29: AGC_TARGET=200");
519	
520	        send_command_ft2232h(8'h2A, 8'h00, 8'h00, 8'h02);  // AGC_ATTACK=2
521	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
522	                8'h2A, 8'h00, 16'h0002, cmd_opcode, cmd_addr, cmd_value);
523	        check(cmd_opcode === 8'h2A && cmd_value === 16'h0002,
524	              "Cmd 0x2A: AGC_ATTACK=2");
525	
526	        send_command_ft2232h(8'h2B, 8'h00, 8'h00, 8'h03);  // AGC_DECAY=3
527	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
528	                8'h2B, 8'h00, 16'h0003, cmd_opcode, cmd_addr, cmd_value);
529	        check(cmd_opcode === 8'h2B && cmd_value === 16'h0003,
530	              "Cmd 0x2B: AGC_DECAY=3");
531	
532	        send_command_ft2232h(8'h2C, 8'h00, 8'h00, 8'h06);  // AGC_HOLDOFF=6
533	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
534	                8'h2C, 8'h00, 16'h0006, cmd_opcode, cmd_addr, cmd_value);
535	        check(cmd_opcode === 8'h2C && cmd_value === 16'h0006,
536	              "Cmd 0x2C: AGC_HOLDOFF=6");
537	
538	        // Self-test / status
539	        send_command_ft2232h(8'h30, 8'h00, 8'h00, 8'h01);  // SELF_TEST_TRIGGER
540	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
541	                8'h30, 8'h00, 16'h0001, cmd_opcode, cmd_addr, cmd_value);
542	        check(cmd_opcode === 8'h30 && cmd_value === 16'h0001,
543	              "Cmd 0x30: SELF_TEST_TRIGGER");
544	
545	        send_command_ft2232h(8'h31, 8'h00, 8'h00, 8'h01);  // SELF_TEST_STATUS
546	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
547	                8'h31, 8'h00, 16'h0001, cmd_opcode, cmd_addr, cmd_value);
548	        check(cmd_opcode === 8'h31 && cmd_value === 16'h0001,
549	              "Cmd 0x31: SELF_TEST_STATUS");
550	
551	        send_command_ft2232h(8'hFF, 8'h00, 8'h00, 8'h00);  // STATUS_REQUEST
552	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
553	                8'hFF, 8'h00, 16'h0000, cmd_opcode, cmd_addr, cmd_value);
554	        check(cmd_opcode === 8'hFF && cmd_value === 16'h0000,
555	              "Cmd 0xFF: STATUS_REQUEST");
556	
557	        // Non-zero addr test
558	        send_command_ft2232h(8'h01, 8'hAB, 8'hCD, 8'hEF);  // addr=0xAB, value=0xCDEF
559	        $fwrite(cmd_file, "%02x %02x %04x %02x %02x %04x\n",
560	                8'h01, 8'hAB, 16'hCDEF, cmd_opcode, cmd_addr, cmd_value);
561	        check(cmd_opcode === 8'h01 && cmd_addr === 8'hAB && cmd_value === 16'hCDEF,
562	              "Cmd 0x01 with addr=0xAB, value=0xCDEF");
563	
564	        $fclose(cmd_file);
565	
566	        // ============================================================
567	        // EXERCISE B: Data Packet Generation
568	        // Inject known values, capture 11-byte output.
569	        // ============================================================
570	        $display("\n=== EXERCISE B: Data Packet Generation ===");
571	        apply_reset;
572	        ft_txe_n = 0;  // TX FIFO ready
573	
574	        // Use distinctive values that make truncation/swap bugs obvious
575	        // range_profile = {Q[15:0], I[15:0]} = {0xCAFE, 0xBEEF}
576	        // doppler_real = 0x1234, doppler_imag = 0x5678
577	        // cfar_detection = 1
578	
579	        // First inject doppler and cfar so pending flags are set
580	        pulse_doppler(16'h1234, 16'h5678);
581	        pulse_cfar(1'b1);
582	
583	        // Now inject range_valid which triggers the write FSM.
584	        // CRITICAL: Must capture bytes IN PARALLEL with the trigger,
585	        // because the write FSM starts sending bytes ~3-4 ft_clk cycles
586	        // after the toggle CDC propagates. If we wait for CDC propagation
587	        // first, capture_write_bytes misses the early bytes.
588	        fork
589	            assert_range_valid(32'hCAFE_BEEF);
590	            capture_write_bytes(11);
591	        join
592	
593	        check(capture_count === 11,
594	              "Data packet: captured 11 bytes");
595	
596	        // Dump captured bytes to file
597	        data_file = $fopen("data_packet.txt", "w");
598	        $fwrite(data_file, "# byte_index hex_value\n");
599	        for (i = 0; i < capture_count; i = i + 1) begin
600	            $fwrite(data_file, "%0d %02x\n", i, captured_bytes[i]);
601	        end
602	        $fclose(data_file);
603	
604	        // Verify locally too
605	        check(captured_bytes[0] === 8'hAA,
606	              "Data pkt: byte 0 = 0xAA (header)");
607	        check(captured_bytes[1] === 8'hCA,
608	              "Data pkt: byte 1 = 0xCA (range MSB = Q high)");
609	        check(captured_bytes[2] === 8'hFE,
610	              "Data pkt: byte 2 = 0xFE (range Q low)");
611	        check(captured_bytes[3] === 8'hBE,
612	              "Data pkt: byte 3 = 0xBE (range I high)");
613	        check(captured_bytes[4] === 8'hEF,
614	              "Data pkt: byte 4 = 0xEF (range I low)");
615	        check(captured_bytes[5] === 8'h12,
616	              "Data pkt: byte 5 = 0x12 (doppler_real MSB)");
617	        check(captured_bytes[6] === 8'h34,
618	              "Data pkt: byte 6 = 0x34 (doppler_real LSB)");
619	        check(captured_bytes[7] === 8'h56,
620	              "Data pkt: byte 7 = 0x56 (doppler_imag MSB)");
621	        check(captured_bytes[8] === 8'h78,
622	              "Data pkt: byte 8 = 0x78 (doppler_imag LSB)");
623	        // Byte 9 = {frame_start, 6'b0, cfar_detection}
624	        // After reset sample_counter==0, so frame_start=1 → 0x81
625	        check(captured_bytes[9] === 8'h81,
626	              "Data pkt: byte 9 = 0x81 (frame_start=1, cfar_detection=1)");
627	        check(captured_bytes[10] === 8'h55,
628	              "Data pkt: byte 10 = 0x55 (footer)");
629	
630	        // ============================================================
631	        // EXERCISE C: Status Packet Generation
632	        // Set known status values, trigger readback, capture 26 bytes.
633	        // Uses distinctive non-zero values to detect truncation/swap.
634	        // ============================================================
635	        $display("\n=== EXERCISE C: Status Packet Generation ===");
636	        apply_reset;
637	        ft_txe_n = 0;
638	
639	        // Set known distinctive status values
640	        status_cfar_threshold  = 16'hABCD;
641	        status_stream_ctrl     = 3'b101;
642	        status_radar_mode      = 2'b11;    // Use 0b11 to test both bits
643	        status_long_chirp      = 16'h1234;
644	        status_long_listen     = 16'h5678;
645	        status_guard           = 16'h9ABC;
646	        status_short_chirp     = 16'hDEF0;
647	        status_short_listen    = 16'hFACE;
648	        status_chirps_per_elev = 6'd42;
649	        status_range_mode      = 2'b10;
650	        status_self_test_flags  = 5'b10101;
651	        status_self_test_detail = 8'hA5;
652	        status_self_test_busy   = 1'b1;
653	        status_agc_current_gain     = 4'd7;
654	        status_agc_peak_magnitude   = 8'd200;
655	        status_agc_saturation_count = 8'd15;
656	        status_agc_enable           = 1'b1;
657	
658	        // Pulse status_request and capture bytes IN PARALLEL
659	        // (same reason as Exercise B — write FSM starts before CDC wait ends)
660	        fork
661	            pulse_status_request;
662	            capture_write_bytes(26);
663	        join
664	
665	        check(capture_count === 26,
666	              "Status packet: captured 26 bytes");
667	
668	        // Dump captured bytes to file
669	        status_file = $fopen("status_packet.txt", "w");
670	        $fwrite(status_file, "# byte_index hex_value\n");
671	        for (i = 0; i < capture_count; i = i + 1) begin
672	            $fwrite(status_file, "%0d %02x\n", i, captured_bytes[i]);
673	        end
674	
675	        // Also dump the raw status_words for debugging
676	        $fwrite(status_file, "# status_words (internal):\n");
677	        for (i = 0; i < 6; i = i + 1) begin
678	            $fwrite(status_file, "# word[%0d] = %08x\n", i, uut.status_words[i]);
679	        end
680	        $fclose(status_file);
681	
682	        // Verify header/footer locally
683	        check(captured_bytes[0] === 8'hBB,
684	              "Status pkt: byte 0 = 0xBB (status header)");
685	        check(captured_bytes[25] === 8'h55,
686	              "Status pkt: byte 25 = 0x55 (footer)");
687	
688	        // Verify status_words[1] = {long_chirp, long_listen} = {0x1234, 0x5678}
689	        check(captured_bytes[5] === 8'h12 && captured_bytes[6] === 8'h34 &&
690	              captured_bytes[7] === 8'h56 && captured_bytes[8] === 8'h78,
691	              "Status pkt: word1 = {long_chirp=0x1234, long_listen=0x5678}");
692	
693	        // Verify status_words[2] = {guard, short_chirp} = {0x9ABC, 0xDEF0}
694	        check(captured_bytes[9] === 8'h9A && captured_bytes[10] === 8'hBC &&
695	              captured_bytes[11] === 8'hDE && captured_bytes[12] === 8'hF0,
696	              "Status pkt: word2 = {guard=0x9ABC, short_chirp=0xDEF0}");
697	
698	        // ============================================================
699	        // Summary
700	        // ============================================================
701	        $display("");
702	        $display("========================================");
703	        $display("  CROSS-LAYER FT2232H TB RESULTS");
704	        $display("  PASSED: %0d / %0d", pass_count, test_num);
705	        $display("  FAILED: %0d / %0d", fail_count, test_num);
706	        if (fail_count == 0)
707	            $display("  ** ALL TESTS PASSED **");
708	        else
709	            $display("  ** SOME TESTS FAILED **");
710	        $display("========================================");
711	
712	        #100;
713	        $finish;
714	    end
715	
716	endmodule
717

