1	/**
2	 * stm32_settings_stub.cpp
3	 *
4	 * Standalone stub that wraps the real RadarSettings class.
5	 * Reads a binary settings packet from a file (argv[1]),
6	 * parses it using RadarSettings::parseFromUSB(), and prints
7	 * all parsed field=value pairs to stdout.
8	 *
9	 * Compile: c++ -std=c++11 -o stm32_settings_stub stm32_settings_stub.cpp \
10	 *          ../../9_Firmware/9_1_Microcontroller/9_1_1_C_Cpp_Libraries/RadarSettings.cpp \
11	 *          -I../../9_Firmware/9_1_Microcontroller/9_1_1_C_Cpp_Libraries/
12	 *
13	 * Usage:  ./stm32_settings_stub packet.bin
14	 *         Prints: field=value lines (one per field)
15	 *         Exit code: 0 if parse succeeded, 1 if failed
16	 */
17	
18	#include "RadarSettings.h"
19	#include <cstdio>
20	#include <cstdlib>
21	
22	int main(int argc, char* argv[]) {
23	    if (argc != 2) {
24	        fprintf(stderr, "Usage: %s <packet.bin>\n", argv[0]);
25	        return 2;
26	    }
27	
28	    // Read binary packet from file
29	    FILE* f = fopen(argv[1], "rb");
30	    if (!f) {
31	        fprintf(stderr, "ERROR: Cannot open %s\n", argv[1]);
32	        return 2;
33	    }
34	
35	    fseek(f, 0, SEEK_END);
36	    long file_size = ftell(f);
37	    fseek(f, 0, SEEK_SET);
38	
39	    if (file_size <= 0 || file_size > 4096) {
40	        fprintf(stderr, "ERROR: Invalid file size %ld\n", file_size);
41	        fclose(f);
42	        return 2;
43	    }
44	
45	    uint8_t* buf = (uint8_t*)malloc(file_size);
46	    if (!buf) {
47	        fprintf(stderr, "ERROR: malloc failed\n");
48	        fclose(f);
49	        return 2;
50	    }
51	
52	    size_t nread = fread(buf, 1, file_size, f);
53	    fclose(f);
